record.field:
# Get selected employees or current employee
employee_ids = env.context.get('active_ids', [])
if not employee_ids:
    employee_ids = [env.context.get('active_id')]

employees = env['hr.employee'].browse(employee_ids)
submitted_count = 0
failed_employees = []

for employee in employees:
    # Get all draft objectives for this employee
    draft_objectives = env['hr.appraisal.goal'].search([
        ('employee_id', '=', employee.id),
        ('state', '=', 'draft')
    ])

    if not draft_objectives:
        continue

    # Check if all have KPIs
    missing_kpi = draft_objectives.filtered(lambda o: not o.kpi_line_ids)
    if missing_kpi:
        failed_employees.append(f"{employee.name} (missing KPIs on {len(missing_kpi)} objectives)")
        continue

    # Submit all draft objectives
    for objective in draft_objectives:
        objective.action_submit()
        submitted_count += 1

# Show result message
if submitted_count:
    message = f"✓ Submitted {submitted_count} objectives"
    if failed_employees:
        message += f"\n⚠ Skipped: {', '.join(failed_employees)}"
    action = {
        'type': 'ir.actions.client',
        'tag': 'display_notification',
        'params': {
            'message': message,
            'type': 'success',
            'sticky': False,
        },
    }
else:
    action = {
        'type': 'ir.actions.client',
        'tag': 'display_notification',
        'params': {
            'message': 'No draft objectives found to submit' + (f"\n⚠ {', '.join(failed_employees)}" if failed_employees else ''),
            'type': 'warning',
            'sticky': False,
        },
    }

# Get selected employees
employee_ids = env.context.get('active_ids', [])
if not employee_ids:
    employee_ids = [env.context.get('active_id')]

employees = env['hr.employee'].browse(employee_ids)
current_uid = env.uid
is_lm = env.user.has_group('hr_appraisal_objectives.group_appraisal_line_manager')
is_hr = env.user.has_group('hr_appraisal_objectives.group_hr_appraisal')

approved_count = 0
skipped_count = 0
approved_employees = set()

current_employee = env['hr.employee'].search([('user_id', '=', current_uid)], limit=1)

for employee in employees:
    objectives = env['hr.appraisal.goal']

    if is_lm:
        # Only first-approve objectives where current user is actually the line manager
        submitted = env['hr.appraisal.goal'].search([
            ('employee_id', '=', employee.id),
            ('state', '=', 'submitted')
        ])
        for obj in submitted:
            manager = obj.manager_id or obj.employee_id.parent_id
            if manager and manager.id == current_employee.id:
                objectives |= obj
    if is_hr:
        # HR can final-approve any first_approved objective
        objectives |= env['hr.appraisal.goal'].search([
            ('employee_id', '=', employee.id),
            ('state', '=', 'first_approved')
        ])

    for objective in objectives:
        # Skip own objectives (self-approval not allowed)
        if objective.employee_id and objective.employee_id.user_id and objective.employee_id.user_id.id == current_uid:
            skipped_count += 1
            continue
        if objective.state == 'submitted':
            objective.action_first_approve()
        elif objective.state == 'first_approved':
            objective.action_second_approve()
        approved_count += 1
        approved_employees.add(employee.name)

# Build result message
no_action_employees = [e.name for e in employees if e.name not in approved_employees]
if approved_count or skipped_count:
    message = f"✓ Approved {approved_count} objectives for {len(approved_employees)} employee(s)"
    if no_action_employees:
        message += f"\n⚠ No approvable objectives found for: {', '.join(no_action_employees)}"
    if skipped_count:
        message += f"\n⚠ Skipped {skipped_count} of your own objectives (self-approval not allowed)"
    action = {
        'type': 'ir.actions.client',
        'tag': 'display_notification',
        'params': {
            'message': message,
            'type': 'success' if approved_count else 'warning',
            'sticky': False,
        },
    }
else:
    action = {
        'type': 'ir.actions.client',
        'tag': 'display_notification',
        'params': {
            'message': 'No objectives awaiting approval found',
            'type': 'warning',
            'sticky': False,
        },
    }

# Get selected employee
employee_id = env.context.get('active_id')
if not employee_id:
    raise UserError("Please select an employee")

employee = env['hr.employee'].browse(employee_id)

# Get objectives awaiting approval
pending_objectives = env['hr.appraisal.goal'].search([
    ('employee_id', '=', employee.id),
    ('state', 'in', ['submitted', 'first_approved'])
])

if not pending_objectives:
    action = {
        'type': 'ir.actions.client',
        'tag': 'display_notification',
        'params': {
            'message': 'No objectives awaiting approval for this employee',
            'type': 'warning',
            'sticky': False,
        },
    }
else:
    # Open wizard to select which objectives to reject
    action = {
        'name': f'Reject Objectives: {employee.name}',
        'type': 'ir.actions.act_window',
        'res_model': 'hr.appraisal.goal.batch.rejection.wizard',
        'view_mode': 'form',
        'target': 'new',
        'context': {
            'default_employee_id': employee.id,
            'default_objective_ids': [(6, 0, pending_objectives.ids)],
        },
    }
